"use client";

import { useState } from "react";
import { Fader } from "@/registry/default/ui/audio/elements/fader";
import { XYPad } from "@/registry/default/ui/audio/elements/xypad";

export default function BlockAtmosMorphPad() {
  const [morph, setMorph] = useState({ x: 0, y: 25 });
  const [mix, setMix] = useState(60);

  return (
    <section className="flex flex-col gap-3 rounded-xl border bg-card p-4">
      <header className="font-medium text-muted-foreground text-xs">
        Atmos Morph
      </header>
      <XYPad
        defaultValue={morph}
        formatValue={(next) => `Color ${next.x} | Space ${next.y}`}
        maxX={100}
        maxY={100}
        minX={-100}
        minY={-100}
        onValueChange={setMorph}
        stepX={1}
        stepY={1}
        value={morph}
      />
      <div className="flex items-center gap-3">
        <span className="font-medium text-muted-foreground text-xs">Wet</span>
        <Fader
          className="h-8 flex-1"
          defaultValue={mix}
          max={100}
          min={0}
          onValueChange={setMix}
          orientation="horizontal"
          value={mix}
        />
        <span className="w-10 text-right font-medium text-muted-foreground text-xs tabular-nums">
          {mix}%
        </span>
      </div>
    </section>
  );
}
